"use client";

import Image from "next/image";
import Link from "next/link";
import { useEffect, useRef } from "react";
import gsap from "gsap";
import HeroText from "./HeroText";
import TalkButton from "./TalkButton";
import TopRightNav from "./TopRightNav";

const NAV_ITEMS = [
  { label: "FRANCIS OLIVER", href: "/about", active: true },
  { label: ".GALLERY", href: "/#gallery", active: false },
  { label: "RESUME", href: "/resume", active: false },
  { label: "PROJECTS", href: "/#projects", active: false },
] as const;

const INTRO =
  "Hi! I'm Francis Oliver, a graduating student at STI College. Thanks for stopping by my website. I aspire to create \"Awwwards\"-level websites like this. I specialize in building web applications using Java with Spring Boot. Feel free to reach out if you'd like me to develop a software application for you.";

const SOCIAL_LINKS = [
  { label: "INSTAGRAM", href: "#" },
  { label: "GITHUB", href: "#" },
  { label: "LINKEDIN", href: "#" },
] as const;

export default function AboutContent() {
  const bottomBarRef = useRef<HTMLElement>(null);
  const heroTextWrapRef = useRef<HTMLDivElement>(null);
  const heroMaskRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const bottomBar = bottomBarRef.current;
    const heroTextWrap = heroTextWrapRef.current;
    const heroMask = heroMaskRef.current;
    if (!bottomBar || !heroTextWrap || !heroMask) return;

    gsap.set(bottomBar, { scaleY: 0, transformOrigin: "bottom center" });
    gsap.set(heroMask, { scaleX: 0, transformOrigin: "left center" });
    gsap.set(heroTextWrap, { opacity: 0, y: 16 });

    const tl = gsap.timeline({ delay: 0.08 });
    tl.to(bottomBar, {
      scaleY: 1,
      duration: 0.9,
      ease: "expo.out",
    })
      .to(
        heroMask,
        {
          scaleX: 1,
          duration: 0.72,
          ease: "power3.inOut",
        },
        "-=0.42"
      )
      .to(
        heroTextWrap,
        {
          opacity: 1,
          y: 0,
          duration: 0.46,
          ease: "power2.out",
        },
        "+=0.06"
      )
      .to(heroMask, {
        opacity: 0,
        duration: 0.18,
        ease: "power1.out",
      });

    return () => {
      tl.kill();
    };
  }, []);

  return (
    <div className="flex h-screen flex-col overflow-hidden bg-white">
      <div className="relative flex w-full shrink-0 flex-col px-4 pt-4 sm:px-6 sm:pt-6 md:px-8 lg:px-10">
        <TopRightNav
          items={NAV_ITEMS}
          className="absolute right-4 top-4 z-10 sm:right-6 sm:top-6"
        />

        <div className="pl-3 max-w-[calc(100vw-8rem)] sm:pl-4 sm:max-w-none sm:pr-28 md:pr-36 lg:max-w-[min(72rem,calc(100vw-18rem))] lg:pr-48 xl:pr-56">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:gap-6 md:gap-7 lg:gap-8 xl:gap-10">
            <div className="relative h-32 w-32 shrink-0 overflow-hidden sm:h-40 sm:w-40 md:h-48 md:w-48 lg:h-44 lg:w-44 xl:h-72 xl:w-72">
              <Image
                src="/assets/profile1.webp"
                alt="Francis Oliver"
                fill
                className="object-cover grayscale"
                sizes="(max-width: 640px) 128px, (max-width: 768px) 160px, (max-width: 1024px) 192px, (max-width: 1280px) 176px, 288px"
                priority
              />
            </div>
            <div className="flex min-w-0 flex-1 flex-col gap-2 sm:gap-3 sm:self-stretch sm:min-h-40 md:min-h-48 lg:min-h-44 xl:min-h-72">
              <p className="max-w-5xl leading-snug tracking-[-0.04em] text-black lg:max-w-none text-xs sm:text-sm md:text-sm lg:text-sm xl:text-lg xl:leading-relaxed xl:tracking-[-0.08em]">
                {INTRO}
              </p>
              <TalkButton />
              <div className="flex flex-wrap gap-3 sm:mt-auto sm:gap-4 xl:gap-6">
                {SOCIAL_LINKS.map(({ label, href }) => (
                  <Link
                    key={label}
                    href={href}
                    className="relative text-[0.65rem] font-medium uppercase tracking-tight text-black sm:text-xs xl:text-sm after:absolute after:left-0 after:top-[calc(100%+2px)] after:h-px after:w-full after:origin-right after:scale-x-0 after:bg-black after:transition-transform after:duration-300 after:ease-out hover:after:origin-left hover:after:scale-x-100"
                  >
                    {label}
                  </Link>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="min-h-8 flex-1" />

      <div className="relative shrink-0 overflow-hidden">
        <div ref={heroTextWrapRef} className="relative z-10 w-fit">
          <HeroText />
        </div>
        <div
          ref={heroMaskRef}
          className="pointer-events-none absolute bottom-0 left-0 z-20 h-full w-full bg-black"
          aria-hidden
        />
      </div>

      <section
        ref={bottomBarRef}
        className="w-full shrink-0 bg-black"
        style={{ height: "30vh" }}
        aria-hidden
      />
    </div>
  );
}
